    Ok(valid) => buffer.push_str(valid),
    Err(err) => {
        tracing::warn!("non-UTF-8 bytes in container output at byte offset {}", err.valid_up_to());
        buffer.push_str(&String::from_utf8_lossy(chunk));
    }
